// // This module selects between two 3-bit inputs, InA and InB, based on the select signal S. When S is high (1), the output Out will reflect the value of InA; when S is low (0), the output will reflect the value of InB.
module top_module(InA, InB, S, Out);input [2:0] InA, InB;
   input       S;
   output [2:0] Out;

   assign Out[0] = (~S & InA[0]) | (S & InB[0]);
   assign Out[1] = (~S & InA[1]) | (S & InB[1]);
   assign Out[2] = (~S & InA[2]) | (S & InB[2]);

endmodule
